import type { Placement } from '@floating-ui/react';
import type React from 'react';
import type { TestComponentProps } from '../../types/test-component';
export type DropdownWithModeType = 'widthContent' | 'widthParent';
export interface NewDropdownMenuProps<PT = HTMLElement> extends TestComponentProps {
    /** Выравнивание по горизонтали */
    align?: Placement;
    /** id корневого тега страницы */
    applicationRootElementID?: string;
    /** Пользовательский класс */
    className?: string;
    /**
     * @deprecated В текущей реализации не используется. Используйте className.
     */
    positionerClassName?: string;
    /** id корневого тега компонента */
    dropdownElementID?: string;
    /**
     * Внешний отступ по горизонтали.
     * @default 0px
     * */
    horizontalOffset?: number;
    /** Внешний отступ по вертикали.
     * @default 8px
     * */
    verticalOffset?: number;
    /** Обработчик события клика вне границ компонента */
    onOutsideClick?: (event: MouseEvent) => void;
    onBlur?: React.FocusEventHandler<PT>;
    /** Колбек который выполнится после открытия дропдавна */
    onOpen?: () => void;
    /** Колбек который выполнится после закрытия дропдавна */
    onClose?: () => void;
    /** Родительский элемент */
    targetElement: React.RefObject<PT>;
    /**
     * Флаг. Указывает на возможность появления скролла внутри DropdownMenu.
     * Учитывается при вычислении позиции.
     * Н-р: Для DatePicker значение должно быть false, чтобы не было скролла внутри DropdownMenu.
     * @default true
     * */
    scrollable?: boolean;
    /**
     * Минимальная высота до которой может сжаться DropdownMenu.
     * Учитывается при вычислении позиции.
     * @default 88px
     * */
    minHeight?: number;
    /**
     * Флаг отвечающий за скрытие/пока dropDownMenu
     * */
    isOpen: boolean;
    /**
     * Устанавливает состояние за скрытие/пока dropDownMenu
     * */
    handleSetOpen: (arg: boolean) => void;
    /**
     * Будет ли ширина dropdown menu подстраиваться под родительский элемент
     * */
    widthMode?: DropdownWithModeType;
    /**
     * Указывает, нужно ли рендерить оверлей
     * */
    shouldRenderOverlay?: boolean;
    /**
     * Добавляет className для Overlay
     * */
    overlayClassName?: string;
    /**
     * скролится ли контент позади выпадающего меню (проброс в FloatingOverlay)
     * */
    overlayScroll?: boolean;
}
